import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import FileExplorer from './components/FileExplorer'; // Add this import to ensure FileExplorer is used
import MicrosoftTeams from './components/MicrosoftTeams';
import Zoom from './components/Zoom';
import Skype from './components/Skype';
import MicrosoftWord from './components/MicrosoftWord';
import MicrosoftExcel from './components/MicrosoftExcel';
import PowerPoint from './components/PowerPoint';
import PDFReader from './components/PDF';
import Chrome from './components/Chrome';
import WhatsApp from './components/WhatsApp';
import Keyboard_mouse from './components/Keyboard_mouse';
import './App.css';

const App = () => {
  const [openWordFiles, setOpenWordFiles] = useState([]);
  const [openExcelFiles, setOpenExcelFiles] = useState([]);
  const [openPptFiles, setOpenPptFiles] = useState([]);
  const [openPdfFiles, setOpenPdfFiles] = useState([]);

  // Funcția pentru adăugarea fișierelor în starea corectă
  const handleFileOpen = (fileName, ext, filePath) => {
    if (['doc', 'docx'].includes(ext)) {
      setOpenWordFiles((prev) => [...prev, { name: fileName, path: filePath }]);
    } else if (['xls', 'xlsx'].includes(ext)) {
      setOpenExcelFiles((prev) => [...prev, { name: fileName, path: filePath }]);
    } else if (['ppt', 'pptx'].includes(ext)) {
      setOpenPptFiles((prev) => [...prev, { name: fileName, path: filePath }]);
    } else if (ext === 'pdf') {
      setOpenPdfFiles((prev) => [...prev, { name: fileName, path: filePath }]);
    }
  };

  return (
    <Router>
      <div className="App">
        <Sidebar
          openWordFiles={openWordFiles}
          openExcelFiles={openExcelFiles}
          openPptFiles={openPptFiles}
          openPdfFiles={openPdfFiles}
        />
        <div className="content">
          <Routes>
            <Route path="/" element={<Navigate to="/shortcuts/fileexplorer" />} />
            <Route
              path="/shortcuts/fileexplorer"
              element={<FileExplorer onFileOpen={handleFileOpen} />}
            />
            <Route path="/shortcuts/teams" element={<MicrosoftTeams />} />
            <Route path="/shortcuts/zoom" element={<Zoom />} />
            <Route path="/shortcuts/skype" element={<Skype />} />
            <Route path="/shortcuts/word" element={<MicrosoftWord />} />
            <Route path="/shortcuts/excel" element={<MicrosoftExcel />} />
            <Route path="/shortcuts/powerpoint" element={<PowerPoint />} />
            <Route path="/shortcuts/pdf" element={<PDFReader />} />
            <Route path="/shortcuts/chrome" element={<Chrome />} />
            <Route path="/shortcuts/whatsapp" element={<WhatsApp />} />
            <Route path="/shortcuts/keyboard_mouse" element={<Keyboard_mouse />} />
          </Routes>
        </div>
      </div>
    </Router>
  );
};

export default App;
